<template>
  <el-button
    :type="type"
    :plain="plain"
    :size="size"
    @click="handleButtonClick"
  >
    <!-- 按钮图标 -->
    <el-icon v-if="icon" :size="iconSize">
      <component :is="icon"></component>
    </el-icon>

    <!-- 自定义内容 -->
    <slot />

    <!-- 按钮文字 -->
    <span v-if="text">{{ text }}</span>
  </el-button>
</template>

<script lang="ts">
import { reactive, toRefs, defineComponent } from 'vue';

export default defineComponent({
  name: 'TButton',
  props: {
    // 按钮文字
    text: {
      type: String,
      required: true,
      default: '按钮',
    },
    type: {
      type: String,
      default: '',
    },
    // 按钮尺寸
    size: {
      type: String,
      default: 'mini',
    },
    plain: {
      type: Boolean,
      default: false,
    },
    // 按钮图标名称
    icon: {
      type: String,
      default: '',
    },
    // 按钮图标尺寸
    iconSize: {
      type: Number,
      default: 13,
    },
  },
  emits: ['click'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({});

    /**
     * 处理按钮点击事件
     */
    const handleButtonClick = () => {
      emit('click');
    };

    return {
      ...toRefs(state),
      handleButtonClick,
    };
  },
});
</script>
