<template>
  <div class="common-base-excel">
    <el-dropdown
      trigger="click"
      @command="handleCommandExcel"
    >
      <el-button
        class="dropdown-button"
        size="mini"
        plain
      >
        <el-icon :size="13">
          <document />
        </el-icon>
        <span>{{ excelTextArr[0].text }}</span>
        <el-icon :size="13" class="el-icon--right">
          <arrow-down />
        </el-icon>
      </el-button>
      <template #dropdown>
        <el-dropdown-menu class="dropdown-menu">
          <el-dropdown-item v-if="uploadExcelUrl.length" command="import">
            <el-icon :size="13">
              <upload />
            </el-icon>
            {{ excelTextArr[1].text }}
          </el-dropdown-item>
          <el-dropdown-item v-if="exportExcelUrl.length" command="export">
            <el-icon :size="13">
              <download />
            </el-icon>
            {{ excelTextArr[2].text }}
          </el-dropdown-item>
          <el-dropdown-item v-if="exportExcelByTemplateUrl.length" command="exportByTemplate">
            <el-icon :size="13">
              <tickets />
            </el-icon>
            {{ excelTextArr[3].text }}
          </el-dropdown-item>
        </el-dropdown-menu>
      </template>
    </el-dropdown>

    <!-- 导入Excel弹框 -->
    <el-dialog
      custom-class="excel-import"
      :model-value="showDialog"
      :close-on-click-modal="false"
      :close-on-press-escape="false"
      @close="onClose"
      @open="onOpen"
    >
      <template #title>
        <span>
          <el-icon :size="16" style="vertical-align: -2px;">
            <info-filled />
          </el-icon>
          导入Excel数据</span>
      </template>

      <div class="m-t-sm m-b-sm flex flex-end">
        <el-button size="small" type="primary" plain @click="handleDownloadModel">
          下载模板
        </el-button>
        <el-button
          size="small"
          type="primary"
          plain
          :loading="loading"
          @click="handleImport"
        >
          导入
        </el-button>
        <el-button size="small" type="primary" plain @click="onClose">
          取消
        </el-button>
      </div>
      <el-input
        v-model="fileName"
        placeholder="请选择excel文件..."
        readonly
        @focus="focusInput"
      >
        <template #prefix>
          <el-icon class="el-input__icon">
            <upload-filled />
          </el-icon>
        </template>
        <template #append>
          <el-button
            size="small"
            @click="focusInput"
          >
            选择
          </el-button>
        </template>
      </el-input>
      <el-upload
        ref="uploadRef"
        :accept="accept"
        :show-file-list="false"
        :multiple="false"
        :action="uploadExcelUrl"
        :data="uploadRequestParam"
        :auto-upload="false"
        :before-upload="beforeUpload"
        :on-error="onError"
        :on-success="onSuccess"
        :on-change="onChange"
        :file-list="fileList"
      >
        <el-button
          id="singleSelectButton"
          style="display: none;"
        />
      </el-upload>
      <div v-if="errorFileName.length">
        <span>错误文件：</span><a href="javascript:void(0)" @click="downLoadErrorFile">{{ errorFileName }}</a>
      </div>
    </el-dialog>
  </div>
</template>

<script lang="ts">
import {
  defineComponent, reactive, toRefs, ref, PropType,
} from 'vue';
import { ElInput, ElMessage } from 'element-plus';
import { UploadFile } from 'element-plus/lib/el-upload/src/upload.type.d';

/**
 * -------------单向绑定初始化参数--------
 * exportExcelUrl: 导出Excel对应的url,get请求，参数拼到url后|非必传|默认空字符串
 * exportExcelByTemplateUrl: 通过模板导出Excel对应的url，get请求，参数拼到url后|非必传|默认空字符串
 * templateDownloadUrl: excel模板下载url,get请求，参数拼到url后|非必传|默认空字符串
 * uploadExcelUrl:  Excel导入url，post请求，参数通过uploadRequestParam传递|非必传|默认空字符串
 * uploadRequestParam: Excel导入携带参数|非必传|默认空对象
 * uploadHeaders: Excel导入携带请求头|非必传|默认空对象
 * ------------------组件回调函数------------
 * on-upload-success : Excel导入成功并且弹窗关闭后触发事件，可以在该事件里刷新页面等。。。
 * ------------------参数格式------------
 * uploadRequestParam: { desigerid: xxx } 一般来说desigerid参数为必传
 */

 interface excelText {
  text: string
 }
export default defineComponent({

  name: 'TExcelButton',
  props: {
    // 导出Excel对应的url,get请求，参数拼到url后
    exportExcelUrl: {
      type: String,
      default: '',
    },
    // 通过模板导出Excel对应的url，get请求，参数拼到url后
    exportExcelByTemplateUrl: {
      type: String,
      default: '',
    },
    // excel模板下载url
    templateDownloadUrl: {
      type: String,
      default: '',
    },
    // Excel导入url，post请求，参数通过uploadRequestParam传递
    uploadExcelUrl: {
      type: String,
      default: '',
    },
    // 导入携带的额外参数
    uploadRequestParam: {
      type: Object,
      default: () => ({}),
    },
    // 文件上传携带请求头
    uploadHeaders: {
      type: Object,
      default: () => ({}),
    },
    // 错误文件下载Url
    errorFileDownloadUrl: {
      type: String,
      default: '',
    },
    // 导出excel按钮文字&下拉框内容
    excelTextArr: {
      type: Array as PropType<excelText[]>,
      default: () => ([
        {text: 'Excel导入/导出示例'},
        {text: '导入Excel'},
        {text: '导出Excel'},
        {text: '导出Excel(by模板)'},
      ])
    }
  },

  emits: ['on-upload-success'],
  setup(props, { emit }) {
    const uploadRef = ref();

    const state = reactive({
      showDialog: false, // 是否显示导入excel弹框
      accept: '.xls, .xlsx', // 可以上传的文件类型
      fileList: [] as UploadFile[], // 上传文件列表
      fileName: '', // 文件名
      errorFileName: '', // 错误文件名
      loading: false, // 导入loading
    });

    /**
     * Excel操作列表触发事件
     */
    function handleCommandExcel(command: string) {
      if (command === 'export') {
        window.location.href = `${props.exportExcelUrl}`;
      } else if (command === 'exportByTemplate') {
        window.location.href = `${props.exportExcelByTemplateUrl}`;
      } else {
        state.showDialog = true;
      }
    }

    /**
     * 关闭导入excel弹框
     */
    function onClose() {
      state.showDialog = false;
    }

    /**
     * input框点击事件
     */
    function focusInput(event: Event) {
      document.getElementById('singleSelectButton')?.click();
      ((event.target as unknown) as typeof ElInput).blur();
    }

    /**
     * 下载模板
     */
    function handleDownloadModel() {
      if (props.templateDownloadUrl?.length) {
        window.location.href = props.templateDownloadUrl;
      } else {
        ElMessage.warning('请设置【templateDownloadUrl】');
      }
    }

    /**
     * 导入
     */
    function handleImport() {
      if (state.fileList.length && state.fileList[0].status === 'ready') {
        if (props.uploadExcelUrl.length === 0) {
          ElMessage.warning('请设置【uploadExcelUrl】对应值');
          return;
        }
        state.loading = true;
        uploadRef.value.submit();
      } else {
        ElMessage.warning('请先选择文件！！！');
      }
    }

    /**
     * 上传文件前调用，如果返回false则停止上传
     */
    function beforeUpload(file: UploadFile) {
      const fileType = file.name.substring(file.name.lastIndexOf('.') + 1);
      if (!state.accept.includes(fileType)) {
        ElMessage.warning(`只允许上传${state.accept}类型文件！！！`);
        return false;
      }
      return true;
    }

    /**
     * 文件上传成功时调用
     */
    function onSuccess(response: CommonBaseHttp.ResponseData, file: UploadFile) {
      state.loading = false;
      if (response.code === 500) {
        ElMessage.error(`导入失败，${response.message}`);
        const tempFile = file;
        tempFile.status = 'ready';
        return;
      }
      if (response.code === 200 && response.data.checked) {
        ElMessage.success('导入成功！！！');
        state.showDialog = false;
        emit('on-upload-success');
      } else {
        const tempFile = file;
        tempFile.status = 'ready';
        state.errorFileName = response.data.errorTempFileName;
        ElMessage.error(`导入失败，${response.data.errorMessage}`);
      }
    }

    /**
     * 文件上传失败时触发事件
     */
    function onError(file: UploadFile) {
      state.loading = false;
      const tempFile = file;
      tempFile.status = 'ready';
      state.fileList.push(tempFile);
      ElMessage.error('导入失败！！！');
    }

    /**
     * 添加文件、上传成功和上传失败时都会被调用
     * 此处主要处理文件名展示问题
     */
    function onChange(file: UploadFile) {
      if (file.status === 'ready') {
        state.fileList = [];
        state.fileName = file.name;
        state.fileList.push(file);
      }
    }

    /**
     * 打开弹窗是触发
     */
    function onOpen() {
      state.fileList = [];
      state.fileName = '';
      state.errorFileName = '';
    }

    /**
     * 下载错误文件
     */
    function downLoadErrorFile() {
      if (!props.errorFileDownloadUrl || !props.errorFileDownloadUrl.length) {
        ElMessage.warning('请设置错误文件下载URL');
        return;
      }
      let errorFileUrl = '';
      if (props.errorFileDownloadUrl.indexOf('?') !== -1) {
        errorFileUrl = `${props.errorFileDownloadUrl}&fileName=${state.errorFileName}`;
      } else {
        errorFileUrl = `${props.errorFileDownloadUrl}?fileName=${state.errorFileName}`;
      }
      window.location.href = errorFileUrl;
    }

    return {
      ...toRefs(state),
      handleCommandExcel,
      onClose,
      onOpen,
      focusInput,
      handleDownloadModel,
      handleImport,
      beforeUpload,
      onSuccess,
      onError,
      onChange,
      uploadRef,
      downLoadErrorFile,
    };
  },
});
</script>

<style lang="scss">
