<template>
  <el-button type="primary" size="small" @click="handleSearch">
    {{ searchBtnName }}
  </el-button>
  <el-button size="small" plain @click="handleReset">
    重置
  </el-button>
  <el-button v-if="isShowFoldBtn" type="text" size="small" @click="toggleFoldState">
    <el-icon :size="14">
      <component :is="buttonIcon"></component>
    </el-icon>
    {{ buttonName }}
  </el-button>
</template>

<script lang="ts">
import { reactive, toRefs, onMounted, watch, defineComponent, PropType, ref } from 'vue';

export default defineComponent({
  name: 'TSearchButton',
  props: {
    // 搜索条件是否展开
    searchShowAll: {
      type: Boolean,
      required: true,
      default: false,
    },
    // 是否隐藏展开按钮
    isShowFoldBtn: {
      type: Boolean,
      default: true,
    },
    // 查询按钮名称
    searchBtnName: {
      type: String,
      default: '查询',
    },
  },
  emits: ['search', 'reset', 'toggle-fold-state'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({
      // 展开/收起按钮名称
      buttonName: '展开',
      // 展开/收起按钮icon标签
      buttonIcon: 'arrow-down',
    });

    /**
     * 查询
     */
    const handleSearch = () => {
      emit('search');
    };

    /**
     * 重置
     */
    const handleReset = () => {
      emit('reset');
    };

    /**
     * 切换 查询条件的 展开与折叠状态
     */
    const toggleFoldState = () => {
      if (!props.searchShowAll) {
        state.buttonName = '收起';
        state.buttonIcon = 'arrow-up';
      } else {
        state.buttonName = '展开';
        state.buttonIcon = 'arrow-down';
      }
      emit('toggle-fold-state', !props.searchShowAll);
    };

    return {
      ...toRefs(state),
      handleSearch,
      handleReset,
      toggleFoldState,
    };
  },
});
</script>
