<template>
  <!-- 文字按钮 -->
  <el-button
    class="text-group-button"
    size="mini"
    type="text"
    :disabled="isDisabled"
    :class="isDelete ? 'delete-text' : ''"
    @click="handleButtonClick()"
  >
    <span>{{ text }}</span>
  </el-button>
  <!-- 右侧竖线 -->
  <span v-if="showSplit" class="text-group-line"></span>
</template>

<script lang="ts">
import { reactive, toRefs, defineComponent } from 'vue';

export default defineComponent({
  name: 'TTextButton',
  props: {
    // 按钮文字
    text: {
      type: String,
      required: true,
      default: '按钮',
    },
    // 是否显示右侧竖线（最后一个按钮不需要）
    showSplit: {
      type: Boolean,
      required: false,
      default: true,
    },
    // 是否禁用
    isDisabled: {
      type: Boolean,
      default: false,
    },
    // 删除按钮
    isDelete: {
      type: Boolean,
      default: false,
    },
  },
  emits: ['click'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({});

    /**
     * 处理按钮点击事件
     */
    const handleButtonClick = () => {
      emit('click');
    };

    return {
      ...toRefs(state),
      handleButtonClick,
    };
  },
});
</script>

<style lang="scss">
/* 表格内部的操作按钮 */
.text-group-button {
  margin: 0 5px;

  &:last-child {
    margin: 0 0 0 5px;
  }
}

/* 表格内部的操作按钮之间的分隔线 */
.text-group-line {
  display: inline-block;
  width: 1px;
  height: 0.6rem;
  background: var(--border-color1);
}
</style>
